"""HTTP request/response handling layer.

Simulates a web framework's HTTP handler. Parses request dicts
and returns response dicts with status codes and bodies.

Request format:  {"method": "GET", "path": "/items/123", "headers": {}, "body": {}}
Response format: {"status": 200, "body": {...}, "headers": {}}
"""
from typing import Any, Dict, Optional
from service import ItemService
from repository import ValidationError, ItemNotFoundError


class Request:
    """Represents an HTTP request."""
    def __init__(self, method: str, path: str, headers: Optional[Dict] = None,
                 body: Optional[Dict] = None, params: Optional[Dict] = None):
        self.method = method
        self.path = path
        self.headers = headers or {}
        self.body = body or {}
        self.params = params or {}


class Response:
    """Represents an HTTP response."""
    def __init__(self, status: int, body: Any = None, headers: Optional[Dict] = None):
        self.status = status
        self.body = body
        self.headers = headers or {}

    def to_dict(self) -> Dict:
        return {"status": self.status, "body": self.body, "headers": self.headers}


class HttpHandler:
    """HTTP request handler that delegates to the service layer.

    Usage:
        handler = HttpHandler(service)
        response = handler.handle(Request("GET", "/items/item1"))
    """

    def __init__(self, service: ItemService):
        self._service = service

    def handle(self, request: Request) -> Response:
        """Route a request to the appropriate handler method."""
        path_parts = request.path.strip("/").split("/")

        if len(path_parts) >= 1 and path_parts[0] == "items":
            if request.method == "GET" and len(path_parts) == 1:
                return self.handle_list(request)
            elif request.method == "GET" and len(path_parts) == 2:
                return self.handle_get(request, path_parts[1])
            elif request.method == "POST" and len(path_parts) == 1:
                return self.handle_create(request)
            elif request.method == "PUT" and len(path_parts) == 2:
                return self.handle_update(request, path_parts[1])
            elif request.method == "DELETE" and len(path_parts) == 2:
                return self.handle_delete(request, path_parts[1])
            elif request.method == "POST" and len(path_parts) == 2 and path_parts[1] == "bulk":
                return self.handle_bulk_update(request)

        return Response(404, {"error": "Not found"})

    def handle_get(self, request: Request, item_id: str) -> Response:
        """Handle GET /items/<id>.

        BUG (Bug 4 partial): Extracts max-age from Cache-Control header
        but does NOT pass it to service.get_item().

        BUG (Bug 5 partial): Uses bare except that returns 500 for
        ALL exceptions, including KeyError from missing items.
        """
        try:
            # Extract max-age from Cache-Control header
            max_age = self._extract_max_age(request.headers)

            # BUG: max_age is extracted but NOT passed to service
            item = self._service.get_item_or_raise(item_id)
            return Response(200, item)
        except Exception:
            # BUG: Bare except catches everything as 500,
            # including KeyError for missing items
            return Response(500, {"error": "Internal server error"})

    def handle_list(self, request: Request) -> Response:
        """Handle GET /items."""
        try:
            items = self._service.list_items()
            return Response(200, items)
        except Exception as e:
            return Response(500, {"error": str(e)})

    def handle_create(self, request: Request) -> Response:
        """Handle POST /items.

        BUG (Bug 2): Passes raw string params from HTTP body
        without type conversion. quantity="5" stays as string,
        causing TypeError in service's quantity * price calculation.
        """
        try:
            data = dict(request.body)

            # BUG: No type conversion — HTTP params are strings!
            # quantity comes as "5" (string) instead of 5 (int)
            # This should convert: data["quantity"] = int(data["quantity"])

            item_id = data.get("id", "")
            if not item_id:
                return Response(400, {"error": "Missing item id"})

            item = self._service.create_item(item_id, data)
            return Response(201, item)
        except ValidationError as e:
            return Response(400, {"error": str(e)})
        except Exception as e:
            return Response(500, {"error": str(e)})

    def handle_update(self, request: Request, item_id: str) -> Response:
        """Handle PUT /items/<id>."""
        try:
            data = dict(request.body)
            item = self._service.update_item(item_id, data)
            return Response(200, item)
        except KeyError:
            return Response(404, {"error": f"Item not found: {item_id}"})
        except ValidationError as e:
            return Response(400, {"error": str(e)})
        except Exception as e:
            return Response(500, {"error": str(e)})

    def handle_delete(self, request: Request, item_id: str) -> Response:
        """Handle DELETE /items/<id>."""
        try:
            deleted = self._service.delete_item(item_id)
            if deleted:
                return Response(204, None)
            return Response(404, {"error": f"Item not found: {item_id}"})
        except Exception as e:
            return Response(500, {"error": str(e)})

    def handle_bulk_update(self, request: Request) -> Response:
        """Handle POST /items/bulk."""
        try:
            updates = request.body.get("updates", [])
            if not updates:
                return Response(400, {"error": "No updates provided"})

            # Convert list of dicts to list of (key, data) tuples
            update_tuples = []
            for update in updates:
                key = update.get("id")
                if not key:
                    return Response(400, {"error": "Each update must have an 'id'"})
                data = {k: v for k, v in update.items() if k != "id"}
                update_tuples.append((key, data))

            results = self._service.bulk_update(update_tuples)
            return Response(200, results)
        except ValidationError as e:
            return Response(400, {"error": str(e)})
        except Exception as e:
            return Response(500, {"error": str(e)})

    def _extract_max_age(self, headers: Dict) -> Optional[int]:
        """Extract max-age from Cache-Control header.

        Parses: 'Cache-Control: max-age=30' -> 30
        """
        cache_control = headers.get("Cache-Control", "")
        if not cache_control:
            return None

        for directive in cache_control.split(","):
            directive = directive.strip()
            if directive.startswith("max-age="):
                try:
                    return int(directive.split("=")[1])
                except (ValueError, IndexError):
                    return None
        return None
